import React, { useState, useEffect, useRef, useCallback } from 'react';

type AudioType = 'question' | 'answer' | 'explanation' | 'generic';

export const useSpeech = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [activeType, setActiveType] = useState<AudioType | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);

  const speakingRef = useRef<boolean>(false);
  const activeUtteranceId = useRef<string | null>(null);

  const loadVoices = useCallback(() => {
    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    let voices = window.speechSynthesis.getVoices();
    if (voices.length === 0) return;

    // Filter for English voices only
    const englishVoices = voices.filter(v => v.lang.startsWith('en'));

    // Scoring system to find the clearest/most natural voice
    const rankedVoices = englishVoices.sort((a, b) => {
        const getScore = (v: SpeechSynthesisVoice) => {
            let score = 0;
            const name = v.name.toLowerCase();
            // Premium/Natural voices (Edge/Azure/Chrome)
            if (name.includes('natural')) score += 100;
            if (name.includes('google') && name.includes('us english')) score += 90;
            if (name.includes('samantha')) score += 80;
            if (name.includes('daniel')) score += 75; 
            if (name.includes('zira')) score += 70;
            if (v.default) score += 50;
            return score;
        };
        return getScore(b) - getScore(a);
    });

    // Select the best voice
    setVoice(rankedVoices[0] || voices[0]);
  }, []);

  useEffect(() => {
    loadVoices();
    if (window.speechSynthesis && window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
    const timer = setTimeout(loadVoices, 500);
    return () => {
      clearTimeout(timer);
      if (typeof window !== 'undefined' && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    };
  }, [loadVoices]);

  const cancel = useCallback(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setSpeakingId(null);
      setActiveType(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    }
  }, []);

  const speak = useCallback((text: string, id: string, type: AudioType = 'generic', e?: React.MouseEvent | React.KeyboardEvent) => {
    if (e) e.stopPropagation();
    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    if (speakingRef.current && activeUtteranceId.current === id) {
      cancel();
      return;
    }

    cancel();

    // ENHANCED MEDICAL PRONUNCIATION & CLEANING
    const cleanText = text
      .replace(/<[^>]*>/g, ' ') // Replace tags with space to avoid merging words
      .replace(/\s+/g, ' ') // Collapse multiple spaces
      // Chemistry / Anatomy specific replacements
      .replace(/Ca2\+/g, 'calcium ions') 
      .replace(/Na\+/g, 'sodium ions')
      .replace(/K\+/g, 'potassium ions')
      .replace(/H\+/g, 'hydrogen ions')
      .replace(/Cl-/g, 'chloride ions')
      .replace(/\bATP\b/g, 'A T P')
      .replace(/\bDNA\b/g, 'D N A')
      .replace(/\bRNA\b/g, 'R N A')
      .replace(/\bCO2\b/g, 'C O 2')
      .replace(/\bO2\b/g, 'oxygen')
      .replace(/\bH2O\b/g, 'water')
      .replace(/°C/g, 'degrees Celsius')
      .replace(/µm/g, 'micrometers')
      // Punctuation for pacing
      .replace(/[\(\[\{]/g, ', ') 
      .replace(/[\)\]\}]/g, ', ')
      .replace(/\//g, ' or ')
      .replace(/&/g, ' and ')
      .replace(/(\d+)\/(\d+)/g, '$1 out of $2') 
      .replace(/([.:;?!])/g, '$1 ')
      .trim();

    // Intelligent Chunking: Split by sentence boundaries
    const rawChunks = cleanText.match(/[^.!?]+[.!?]+(?=\s|$)|[^.!?]+$/g) || [cleanText];
    const chunks = rawChunks.map(c => c.trim()).filter(c => c.length > 0);

    if (chunks.length === 0) return;

    activeUtteranceId.current = id;
    speakingRef.current = true;
    setIsSpeaking(true);
    setSpeakingId(id);
    setActiveType(type);

    let currentChunkIndex = 0;

    const speakNextChunk = () => {
        if (currentChunkIndex >= chunks.length || !speakingRef.current) {
            setIsSpeaking(false);
            setSpeakingId(null);
            setActiveType(null);
            speakingRef.current = false;
            activeUtteranceId.current = null;
            return;
        }

        const chunkText = chunks[currentChunkIndex];
        const utterance = new SpeechSynthesisUtterance(chunkText);

        if (voice) {
            utterance.voice = voice;
            utterance.lang = voice.lang;
        } else {
            utterance.lang = 'en-US';
        }

        // TUNED FOR CLARITY
        utterance.rate = 0.9;  // Clear, deliberate speed
        utterance.pitch = 1.0; // Natural pitch
        utterance.volume = 1.0; // Max volume

        utterance.onend = () => {
            currentChunkIndex++;
            speakNextChunk();
        };

        utterance.onerror = (event) => {
            console.error("Speech Error:", event);
            currentChunkIndex++;
            speakNextChunk();
        };

        window.speechSynthesis.speak(utterance);
    };

    speakNextChunk();

  }, [voice, cancel]);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId,
    activeType,
    hasSupport: typeof window !== 'undefined' && 'speechSynthesis' in window
  };
};

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, Maximize2, X, ChevronLeft, ChevronRight, Volume2, VolumeX } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
    setDirection('none');
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel(); // Stop audio when changing cards
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = () => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(!isFlipped);
      cancel(); // Stop audio on flip
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const nextCard = () => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  };

  const prevCard = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  };

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const currentCard = deck[currentIndex];

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col max-w-5xl mx-auto w-full px-4 pb-4">

      {/* --- ZOOM MODAL --- */}
      {zoomedImage && (
        <div className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-4 animate-in fade-in duration-200" onClick={() => setZoomedImage(null)}>
          <button className="absolute top-4 right-4 text-white/70 hover:text-white p-2 transition-colors">
            <X size={32} />
          </button>
          <img 
            src={zoomedImage} 
            className="max-w-full max-h-full object-contain rounded-md shadow-2xl animate-in zoom-in-95 duration-300" 
            alt="Enlarged view" 
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      )}

      {/* --- TOP CONTROLS (Compact) --- */}
      <div className="flex-none mb-4 flex justify-between items-center gap-3 z-20">
        <div className="flex items-center gap-3">
            <div className="bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm font-black text-slate-700 text-xs tracking-wider">
            {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0'}
            </div>

            {/* Filter Dropdown */}
            <div className="relative">
                <Button 
                variant="ghost" 
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className={`flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider rounded-lg border h-8 px-3 ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200 text-slate-500'}`}
                >
                <Filter size={12} />
                {selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'Topic'}
                <ChevronDown size={10} className={`transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} />
                </Button>

                {isFilterOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                    <div 
                      className="absolute left-0 top-full mt-2 w-72 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 flex flex-col max-h-[50vh]"
                      onClick={(e) => e.stopPropagation()}
                    >
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center rounded-t-xl">
                        <span className="text-xs font-bold text-slate-500 uppercase">Select Chapters</span>
                        <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-red-500 hover:text-red-700">Reset All</button>
                    </div>
                    <div className="overflow-y-auto p-2 custom-scrollbar">
                        {categories.map(cat => (
                        <label key={cat} className="flex items-center gap-3 p-2.5 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors">
                            <div className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                            {selectedCategories.includes(cat) && <Check size={10} className="text-white" />}
                            </div>
                            <span className="text-xs font-bold text-slate-700 leading-tight">{cat}</span>
                            <input 
                            type="checkbox" 
                            className="hidden"
                            checked={selectedCategories.includes(cat)}
                            onChange={() => toggleCategory(cat)}
                            />
                        </label>
                        ))}
                    </div>
                    </div>
                </>
                )}
            </div>
        </div>

        <Button 
            variant="ghost" 
            onClick={() => {
              const shuffled = [...deck].sort(() => Math.random() - 0.5);
              setDeck(shuffled);
              setCurrentIndex(0);
              setIsFlipped(false);
              setDirection('none');
            }} 
            className="h-8 px-3 text-[10px] font-bold text-slate-500 bg-white border border-slate-200 rounded-lg uppercase tracking-wider hover:text-blue-600 hover:border-blue-200"
        >
            <Shuffle size={12} className="mr-1" /> Shuffle
        </Button>
      </div>

      {/* --- THE CARD (Flexible Height) --- */}
      <div className="flex-1 min-h-0 relative perspective-1000 z-10 group mb-4">
        {deck.length > 0 && currentCard ? (
            <div 
                key={currentCard.id}
                className={`w-full h-full relative transform-style-3d transition-all duration-500 ease-in-out cursor-pointer ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
                onClick={flipCard}
            >

            {/* FRONT (Question) */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-3xl shadow-[0_4px_20px_rgb(0,0,0,0.05)] border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="px-6 pt-5 flex justify-between items-start flex-none">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50 px-3 py-1 rounded-full border border-slate-100">
                  Question
                </span>

                {hasSupport && (
                  <button 
                    onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')}
                    className={`p-2 rounded-full transition-colors ${isSpeaking && speakingId === currentCard.id + 'q' ? 'bg-red-100 text-red-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-900'}`}
                    title="Read Question"
                  >
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div 
                    className="mb-6 flex-none bg-slate-50 p-2 rounded-xl border border-slate-100 relative group/img hover:border-blue-300 transition-colors cursor-zoom-in max-h-[45%]"
                    onClick={(e) => { e.stopPropagation(); setZoomedImage(currentCard.questionImage!); }}
                  >
                    <img 
                      src={currentCard.questionImage} 
                      className="max-h-full w-auto object-contain rounded-lg mix-blend-multiply"
                      onError={() => setImgError(true)}
                      alt="Question Diagram"
                    />
                    <div className="absolute top-2 right-2 bg-white/90 p-1.5 rounded-lg text-slate-500 opacity-0 group-hover/img:opacity-100 transition-opacity shadow-sm">
                      <Maximize2 size={14} />
                    </div>
                  </div>
                )}
                <div 
                  className="text-lg md:text-xl font-extrabold text-center text-slate-900 leading-snug"
                  dangerouslySetInnerHTML={{ __html: currentCard.questionText }}
                />
              </div>
              <div className="h-8 flex-none bg-slate-50 border-t border-slate-100 flex items-center justify-center text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em]">
                Tap Card to Flip
              </div>
            </div>

            {/* BACK (Answer) */}
            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-3xl shadow-[0_20px_50px_rgb(15,23,42,0.3)] border border-slate-800 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="px-6 pt-5 flex justify-between items-center flex-none">
                <span className="text-[10px] font-black uppercase text-emerald-400 tracking-[0.2em] bg-emerald-400/10 px-3 py-1 rounded-full border border-emerald-400/20">
                  Answer
                </span>

                {hasSupport && (
                  <button 
                    onClick={(e) => handleAudio(e, currentCard.answerText + ". " + (currentCard.explanation || ""), currentCard.id + 'a')}
                    className={`p-2 rounded-full transition-colors ${isSpeaking && speakingId === currentCard.id + 'a' ? 'bg-red-500/20 text-red-400' : 'bg-white/10 text-white/50 hover:bg-white/20 hover:text-white'}`}
                    title="Read Answer"
                  >
                    {isSpeaking && speakingId === currentCard.id + 'a' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.answerImage && !ansImgError && (
                  <div 
                    className="mb-6 flex-none bg-white p-2 rounded-xl relative group/img cursor-zoom-in max-h-[45%]"
                    onClick={(e) => { e.stopPropagation(); setZoomedImage(currentCard.answerImage!); }}
                  >
                    <img 
                      src={currentCard.answerImage} 
                      className="max-h-full w-auto object-contain rounded-lg"
                      onError={() => setAnsImgError(true)}
                      alt="Answer Diagram"
                    />
                    <div className="absolute top-2 right-2 bg-black/10 p-1.5 rounded-lg text-slate-700 opacity-0 group-hover/img:opacity-100 transition-opacity">
                      <Maximize2 size={14} />
                    </div>
                  </div>
                )}

                <div 
                  className="text-lg md:text-2xl font-bold text-center text-white leading-relaxed mb-4"
                  dangerouslySetInnerHTML={{ __html: currentCard.answerText }}
                />

                {currentCard.explanation && (
                  <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50 text-slate-300 text-sm leading-relaxed max-w-lg text-center backdrop-blur-sm">
                    <span className="text-slate-500 font-bold uppercase text-[10px] tracking-widest block mb-1">Explanation</span>
                    <span dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                  </div>
                )}
              </div>
              <div className="h-8 flex-none bg-slate-950/30 border-t border-slate-800/50 flex items-center justify-center text-[9px] font-bold text-slate-600 uppercase tracking-[0.2em]">
                Tap to Flip Back
              </div>
            </div>
          </div>
        ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-white rounded-3xl border-2 border-dashed border-slate-300 text-slate-400 p-8 text-center">
                <Filter size={48} className="mb-4 opacity-20" />
                <p className="font-bold text-lg">No cards found in this filter.</p>
                <button onClick={() => setSelectedCategories([])} className="mt-2 text-blue-500 font-bold hover:underline">Reset Filters</button>
            </div>
        )}
      </div>

      {/* --- BOTTOM CONTROLS (Navigation) --- */}
      <div className="flex-none flex items-center justify-center gap-4 w-full">
        <button 
          onClick={prevCard}
          disabled={currentIndex === 0}
          className="h-14 w-16 md:w-20 rounded-2xl bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 hover:shadow-lg transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center shrink-0"
        >
          <ChevronLeft size={28} />
        </button>

        <button 
          onClick={flipCard} 
          className="h-14 flex-1 max-w-xs rounded-2xl bg-slate-900 text-white font-bold uppercase tracking-widest shadow-xl shadow-slate-900/20 hover:bg-blue-600 hover:shadow-blue-600/30 hover:-translate-y-1 active:translate-y-0 transition-all flex items-center justify-center gap-3 text-xs"
        >
          <RotateCw size={16} className={isFlipped ? "-rotate-180 transition-transform duration-500" : "transition-transform duration-500"} />
          {isFlipped ? 'Question' : 'Answer'}
        </button>

        <button 
          onClick={nextCard}
          disabled={currentIndex === deck.length - 1}
          className="h-14 w-16 md:w-20 rounded-2xl bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 hover:shadow-lg transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center shrink-0"
        >
          <ChevronRight size={28} />
        </button>
      </div>
    </div>
  );
};

export default Flashcards;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, Download, Upload, ShieldCheck, Database, 
  Filter, ArrowUpDown, X, ChevronDown, Check, Highlighter,
  Volume2, VolumeX
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const ITEMS_PER_PAGE = 20;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  // Helper to remove HTML tags for searching and sorting (still used for search)
  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  // Helper to escape regex characters
  const escapeRegExp = (string: string) => {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  };

  // Helper to highlight matched terms
  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;

    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;

    terms.forEach(term => {
      const regex = new RegExp(`(${escapeRegExp(term)})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-yellow-300 text-slate-900 rounded-sm px-0.5 font-bold">$1</mark>');
    });

    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'Uncategorized'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (selectedCategory !== 'All') {
      result = result.filter(q => (q.category || 'Uncategorized') === selectedCategory);
    }

    if (search.trim()) {
      const terms = search.toLowerCase().split(/\s+/).filter(Boolean);

      result = result.filter(q => {
        const qText = stripHtml(q.questionText).toLowerCase();
        const aText = stripHtml(q.answerText).toLowerCase();
        return terms.every(term => qText.includes(term) || aText.includes(term));
      });
    }

    if (sortOrder === 'asc') {
      result = [...result].sort((a, b) => stripHtml(a.questionText).localeCompare(stripHtml(b.questionText)));
    } else if (sortOrder === 'desc') {
      result = [...result].sort((a, b) => stripHtml(b.questionText).localeCompare(stripHtml(a.questionText)));
    }

    return result;
  }, [data, selectedCategory, search, sortOrder]);

  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategory, sortOrder]);

  useEffect(() => {
    return () => cancel();
  }, [currentPage, cancel]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  const handlePageChange = (newPage: number) => {
    cancel();
    setCurrentPage(newPage);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="max-w-7xl mx-auto w-full px-4 py-6 md:py-8 space-y-6 pb-32">
      <div className="bg-white rounded-3xl p-6 md:p-8 border border-slate-200 shadow-xl overflow-hidden relative group">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
          <Database size={200} />
        </div>

        <div className="flex flex-col md:flex-row justify-between gap-6 relative z-10">
          <div className="space-y-2">
